mapper.select:
SELECT COUNT(*) FROM audit_record ar
ar.biz_type = 'ARTICLE'
AND ar.audit_status = #{auditStatus}

SELECT ar.id, ar.biz_type as bizType, ar.article_id as articleId, ar.audit_status as auditStatus, ar.audit_type as auditType, ar.auditor_id as auditorId, ar.reason, ar.created_at as createdAt, ar.updated_at as updatedAt,
a.title, a.summary, a.cover_image as coverImage, a.word_count as wordCount, a.created_at as articleCreatedAt,
u.id as authorId, u.nickname as authorNickname, u.avatar as authorAvatar,
au.nickname as auditorNickname,
GROUP_CONCAT(at.name SEPARATOR ', ') as tags
FROM audit_record ar LEFT JOIN article a ON ar.article_id = a.id LEFT JOIN user u ON a.user_id = u.id LEFT JOIN user au ON ar.auditor_id = au.id LEFT JOIN article_tag_relation atr ON a.id = atr.article_id LEFT JOIN article_tag at ON atr.tag_id = at.id
ar.biz_type = 'ARTICLE'
AND ar.audit_status = #{auditStatus}
AND ar.auditor_id = #{auditorId}
GROUP BY ar.id, a.id, u.id, au.id ORDER BY ar.updated_at DESC LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(*)
FROM audit_record ar

    ar.biz_type = 'ARTICLE'

        AND ar.audit_status = #{auditStatus}


        AND ar.auditor_id = #{auditorId}

SELECT *
FROM audit_record
WHERE biz_type = 'ARTICLE' AND article_id = #{articleId}

SELECT ar.id,ar.biz_type as bizType,ar.article_id as articleId, ar.audit_status as auditStatus,ar.audit_type as auditType, ar.auditor_id as auditorId,ar.reason, ar.created_at as createdAt,ar.updated_at as updatedAt,
a.title,a.summary,a.cover_image as coverImage, a.view_count as viewCount,a.like_count as likeCount, a.comment_count as commentCount, a.collect_count as collectCount, a.share_count as shareCount, a.word_count as wordCount,a.created_at as articleCreatedAt,
u.id as authorId,u.nickname as authorNickname, u.avatar as authorAvatar,
au.nickname as auditorNickname, GROUP_CONCAT(DISTINCT at.name ORDER BY at.name SEPARATOR ', ') AS tags, c9.name as categoryName
FROM audit_record ar LEFT JOIN article a ON ar.article_id = a.id LEFT JOIN user u ON a.user_id = u.id LEFT JOIN user au ON ar.auditor_id = au.id LEFT JOIN category c9 ON a.category_id = c9.id left join article_tag_relation atr on a.id = atr.article_id left join article_tag at on at.id = atr.tag_id
ar.biz_type = 'ARTICLE'
AND ar.audit_status = #{request.auditStatus}
AND (a.title LIKE CONCAT('%', #{request.title}, '%') or u.nickname LIKE CONCAT('%', #{request.title}, '%') )
and a.category_id IN ( WITH RECURSIVE category_tree AS ( SELECT id FROM category WHERE id = #{request.categoryId} UNION ALL SELECT c.id FROM category c INNER JOIN category_tree ct ON c.parent_id = ct.id ) SELECT id FROM category_tree )
AND ar.audit_type = #{request.auditType}
AND ar.auditor_id = #{request.auditorId}
AND a.created_at >= #{request.startTime}
AND a.created_at <= #{request.endTime}
AND ar.updated_at >= #{request.auditStartTime}
AND ar.updated_at <= #{request.auditEndTime}
GROUP BY ar.id, a.id, u.id, au.id, c9.id ORDER BY ar.created_at DESC LIMIT #{request.pageSize} OFFSET #{offset}

SELECT COUNT(DISTINCT ar.id)
FROM audit_record ar
LEFT JOIN article a ON ar.article_id = a.id
LEFT JOIN user u ON a.user_id = u.id
LEFT JOIN category c ON a.category_id = c.id

    ar.biz_type = 'ARTICLE'

        AND ar.audit_status = #{request.auditStatus}


        AND a.title LIKE CONCAT('%', #{request.title}, '%')


        AND u.nickname LIKE CONCAT('%', #{request.authorName}, '%')


        AND a.category_id = #{request.categoryId}


        AND ar.audit_type = #{request.auditType}


        AND ar.auditor_id = #{request.auditorId}


        AND a.created_at >= #{request.startTime}


        AND a.created_at <= #{request.endTime}


        AND ar.updated_at >= #{request.auditStartTime}


        AND ar.updated_at <= #{request.auditEndTime}
